import React from 'react';

const Projects = () => {
  const projectList = [
    { title: 'Face Recognition SDV', description: 'Smart vehicle system with facial authentication' },
    { title: 'E-commerce Site', description: 'Full-stack shopping platform with React and Express' },
  ];

  return (
    <section id="projects" style={styles.section}>
      <h2>Projects</h2>
      <div style={styles.projectGrid}>
        {projectList.map((project, index) => (
          <div key={index} style={styles.card}>
            <h3>{project.title}</h3>
            <p>{project.description}</p>
          </div>
        ))}
      </div>
    </section>
  );
};

const styles = {
  section: {
    padding: '4rem 2rem', backgroundColor: '#f0f0f0', textAlign: 'center'
  },
  projectGrid: {
    display: 'flex', gap: '1.5rem', justifyContent: 'center', flexWrap: 'wrap', marginTop: '2rem'
  },
  card: {
    backgroundColor: '#fff', padding: '1.5rem', borderRadius: '10px',
    width: '250px', boxShadow: '0 2px 5px rgba(0,0,0,0.1)'
  }
};

export default Projects;
